#define CAN0_MR_RXSYNC_SINGLE_P  0x02000000 // Rx Signal with Single Synchro Stage (Positive Edge)
#define CAN0_MR_RXSYNC_NONE      0x03000000 // Rx Signal with No Synchro Stage

