#define DMAC_CTRLA0_DST_WIDTH_HALF_WORD 0x10000000                // the transfer size is set to 16-bit width
#define DMAC_CTRLA0_DST_WIDTH_WORD      0x20000000                // the transfer size is set to 32-bit width
